sql:
SELECT AVG(
    CAST(strftime('%Y', 'now') - strftime('%Y', date_of_birth) - 
         (strftime('%m%d', 'now') < strftime('%m%d', date_of_birth)) AS REAL)
) AS Average_Age
FROM runners
WHERE is_active = 1;

SELECT name, city 
FROM runners 
WHERE is_active = 1;

SELECT runners.name, runners.state
FROM runners
WHERE runners.runner_id IN (
    SELECT performances.runner_id
    FROM performances
)
AND runners.runner_id NOT IN (
    SELECT runner_teams.runner_id
    FROM runner_teams
);

SELECT runners.name, runners.age_group
FROM runners
JOIN performances ON runners.runner_id = performances.runner_id;

SELECT DISTINCT r.name
FROM runners r
JOIN performances p ON r.runner_id = p.runner_id;

external_knowledge:
- "swift-footed racers" refers to runners who have completed a marathon with a minimum finish time;
- "squadrons" are the teams to which the runners belong;
- "contests" represent different marathons;
- "broke the barriers of time the swiftest" means achieving the fastest finish time in a marathon.

sql:
SELECT DISTINCT r.name, r.age_group, r.city, r.state
FROM runners r
INNER JOIN performances p ON r.runner_id = p.runner_id;

SELECT AVG(
    strftime('%Y', 'now') - strftime('%Y', date_of_birth) - 
    (strftime('%m%d', 'now') < strftime('%m%d', date_of_birth))
) AS avg_age
FROM runners
WHERE runner_id IN (
    SELECT runner_id FROM performances
);

SELECT runners.name, runner_teams.team_id
FROM runners
INNER JOIN runner_teams ON runners.runner_id = runner_teams.runner_id;

external_knowledge:
- "sprinted past" metaphorically means having a chip time faster than;
- "spirited racers" refers to runners;
- "slowest team captain" metaphorically refers to the team leader with the maximum chip time;
- "speed" in the context represents the chip time of runners;
- "count" refers to the number of runners satisfying the criteria.
